// Extract base64 images array from body
const body = $input.first().json.body || $input.first().json;
const images = body.images || [];
const items = [];
for (const img of images) {
  items.push({ json: { image_base64: img, original_body: body } });
}
if (items.length === 0) {
  items.push({ json: { image_base64: null, original_body: body } });
}
return items;

// Parse Claude response into lead fields
const response = $input.first().json;
let content = '';
try {
  content = response.content[0].text;
} catch(e) {
  throw new Error('Claude response malformed: ' + JSON.stringify(response));
}

// Strip markdown code fences if present
content = content.replace(/^```json\n?/, '').replace(/\n?```$/, '').trim();

let lead;
try {
  lead = JSON.parse(content);
} catch(e) {
  throw new Error('Claude did not return valid JSON: ' + content);
}

return [{ json: lead }];
